# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json

class GameServer:
    def __init__(self):
        self.connected_players = {}
        self.inventories = {}

    async def handler(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            cmd = data.get('command')

            if cmd == 'connect':
                player_id = data.get('player_id')
                self.connected_players[player_id] = websocket
                self.inventories.setdefault(player_id, [])
                await websocket.send(json.dumps({"status": "connected"}))

            elif cmd == 'trade':
                from_id = data.get('from_id')
                to_id = data.get('to_id')
                item = data.get('item')
                if item in self.inventories[from_id]:
                    if to_id in self.connected_players:
                        self.inventories[from_id].remove(item)
                        self.inventories.setdefault(to_id, []).append(item)
                        await websocket.send(json.dumps({"status": "trade_successful"}))
                        await self.connected_players[to_id].send(json.dumps({"status": "received_item", "item": item}))
                    else:
                        await websocket.send(json.dumps({"status": "player_not_connected"}))
                else:
                    await websocket.send(json.dumps({"status": "item_not_available"}))

    async def start_server(self):
        async with websockets.serve(self.handler, "localhost", 8765):
            await asyncio.Future()  # Run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())